import { Component, EventEmitter, Input, Output } from '@angular/core';

@Component({
  selector: 'app-course-card',
  templateUrl: './course-card.component.html',
  styleUrls: ['./course-card.component.scss']
})
export class CourseCardComponent {
  @Input() isEditable: boolean = true;
  @Output() clickOnShow = new EventEmitter(); // create new clickOnShow event

  title: string = 'Sample title';
  description: string = 'Description sample';
  creationDate: Date = new Date();
  duration: number = 10;
  authors: string[] = ['Tsvetelin Naydenov', 'Rustam Levkovsky']

  onShowClick(){
    this.clickOnShow.emit(); // emit the event to the parent component
  }
}
<div class="course-card">
    <div class="course-card__description">
      <!-- Replace ::text:: with your code -->
      <div class="course-card__description-title">{{ title }}</div>
      <div class="course-card__description-text">{{ description }}</div>
    </div>
    <div class="course-card__info">
        <div class="course-card__info-text">
            <div>
              <b>Authors: </b>{{ authors.join(', ') }}
            </div>
            <div><b>Duration: </b><span class="course-card__duration">{{ duration }}</span></div>
            <div><b>Created: </b><span class="course-card__date">{{ creationDate }}</span></div>
        </div>
        <div class="course-card__info-actions">
            <app-button buttonText="Show Course" (click)="onShowClick()"></app-button>
            <div class="course-card__buttons" *ngIf="isEditable">
                <ng-content></ng-content>
            </div>
        </div>
    </div>
</div>
